// Node 4 - Split Pages (Run Once for All Items)

const resp = $json?.body ?? $json;

// Extract text from Responses API output
function getText(r) {
  if (!r || !Array.isArray(r.output)) throw new Error("No `output` array in OpenAI response.");
  for (const item of r.output) {
    for (const c of (item.content ?? [])) {
      if (typeof c?.text === "string" && c.text.trim()) return c.text;
    }
  }
  throw new Error("No text found inside `output.content.text`.");
}

const parsed = JSON.parse(getText(resp));

const pages = [
  { title: parsed.about_title, body_html: parsed.about_body_html },
  { title: parsed.shipping_title, body_html: parsed.shipping_body_html },
  { title: parsed.faq_title, body_html: parsed.faq_body_html },
  { title: parsed.contact_title, body_html: parsed.contact_body_html }
];

return pages.map(p => ({ json: p }));
